mapper.select:
/* ====== cmn.accesslogsrch.selectList =========*/
SELECT TO_CHAR(a.LOG_DTTM, 'YYYY-MM-DD HH24:MI:SS') LOG_DTTM , a.IP_INFO , a.MAC_ADDR , a.SUCC_YN , a.REGST_PRGM , a.REGSTST_ID , a.USR_ID , b.usr_nm , B.ORGN_ID , FN_GET_ORGNM(B.ORGN_ID) AS ORGN_NM , TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') REGST_DTTM FROM CMN_USR_CNNCT_LOG_HST a, CMN_USR_MST B, ORG_ORGN_INFO_MST C WHERE A.USR_ID = B.USR_ID(+) AND B.ORGN_ID = C.ORGN_ID(+)
AND B.ORGN_ID = #{orgnId}
AND A.USR_ID = #{searchUsrId}
AND A.LOG_DTTM >= TO_DATE(#{searchStrtDt}, 'YYYYMMDD')
AND A.LOG_DTTM < TO_DATE(#{searchEndDt}, 'YYYYMMDD') + 1
ORDER BY a.LOG_DTTM DESC
